import{_ as d,o as r,c as a,a2 as p}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1963年/年中信.md","filePath":"01_letters/1963年/年中信.md"}'),e={name:"01_letters/1963年/年中信.md"};function h(o,t,l,i,n,b){return r(),a("div",null,[...t[0]||(t[0]=[p('<h2 id="_1963年上半年业绩" tabindex="-1">1963年上半年业绩 <a class="header-anchor" href="#_1963年上半年业绩" aria-label="Permalink to &quot;1963年上半年业绩&quot;">​</a></h2><p>1963年上半年，道琼斯工业平均指数（下称“道指”）从652.10点上涨至706.88点。如果在此期间持有道指成分股，将获得10.66点的股息，折算下来，道指上半年的整体收益率为**+10.0%**。</p><p>我们一直反复强调两点：</p><ol><li><p>短期业绩（少于三年）几乎没有参考意义，尤其是对于我们这种将部分资金配置于控股类投资的运作模式而言；</p></li><li><p>相对道指和其他普通股投资工具，我们的业绩在下跌市场中会更具优势，而在市场狂热上涨的阶段，很可能只能勉强跟上大盘，甚至跑不赢。</p></li></ol><p>尽管如此，我们上半年的业绩（剔除邓普斯特公司的估值变动，其估值确实发生了变化——我会在信的后半部分详细说明）依然达到了**+14%**。</p><p>这14%的收益率，基于基金总净资产计算（而非剔除邓普斯特后的资产），已扣除所有费用，未扣除向合伙人的月度提款（针对选择提款的合伙人），以及普通合伙人的业绩报酬。</p><p>interim阶段的业绩分配没有实际意义，但如果全年收益率同样是14%，那么前6%的收益将全部按合伙人的出资比例分配，剩余8%的收益中，四分之三（即额外6%）也将分配给有限合伙人，最终有限合伙人的全年收益率为12%。</p><p>尽管上半年取得了不错的业绩，前文的两个核心观点依然完全成立。上半年我们收益率14%，道指10%，但这六个月的表现，在我看来远不如1962年上半年——当时我们收益率-7.5%，而道指收益率-21.7%。大家必须完全理解我们的这一理念，这在过往的信件中也反复强调过。</p><p>上半年，我们在低估类投资上的平均净持仓（低估股多头仓位减去空头仓位）约为527.5万美元，从这类投资中获得的总收益约为110万美元，对应收益率约为21%。</p><p>这再次印证了，资金在不同投资品类之间的分配，会对短期业绩产生多大的影响。1962年全年，低估类投资整体下跌，正是依靠另外两个品类——套利类和控股类投资的出色表现，我们才取得了当年远超市场的业绩。</p><p>而今年，在市场上涨的环境中，套利类投资的表现不如道指，拖累了整体业绩——这本来就在我们的预期之中。虽然在市场上涨时满仓低估股、下跌时满仓套利股，能让业绩变得非常好看，但我绝不会去做这种预判股市走势的事情。</p><p>我们认为，长期来看，这三类投资都是优质的投资方向，只是在不同的市场环境中，它们的短期价格表现特征有显著差异。而试图预测股市的短期波动，长期来看是一门极差的生意，我们绝不会涉足，无论是直接择时，还是通过预判哪类投资短期表现更好来间接择时，我们都不会做。</p><h3 id="投资公司业绩对比" tabindex="-1">投资公司业绩对比 <a class="header-anchor" href="#投资公司业绩对比" aria-label="Permalink to &quot;投资公司业绩对比&quot;">​</a></h3><p>下表列示了道指、巴菲特合伙有限公司（含前身合伙基金），以及两家规模最大的普通股策略开放式共同基金、两家规模最大的多元化封闭式投资公司的累计业绩：</p><table tabindex="0"><thead><tr><th>统计区间</th><th>道琼斯指数</th><th>马萨诸塞投资者信托（1）</th><th>投资者股票基金（1）</th><th>大陆公司（2）</th></tr></thead><tbody><tr><td>1957年</td><td>-8.4%</td><td>-11.4%</td><td>-12.4%</td><td>-2.4%</td></tr><tr><td>1957-1958年</td><td>26.9%</td><td>26.4%</td><td>29.2%</td><td>30.0%</td></tr><tr><td>1957-1959年</td><td>52.3%</td><td>37.8%</td><td>42.5%</td><td>40.9%</td></tr><tr><td>1957-1960年</td><td>42.9%</td><td>36.4%</td><td>41.6%</td><td>44.8%</td></tr><tr><td>1957-1961年</td><td>74.9%</td><td>71.3%</td><td>76.9%</td><td>77.4%</td></tr><tr><td>1957-1962年</td><td>61.6%</td><td>54.5%</td><td>53.2%</td><td>59.7%</td></tr><tr><td>1957-1963年6月30日</td><td>77.8%</td><td>72.4%</td><td>69.3%</td><td>75.7%</td></tr><tr><td>年化复合收益率</td><td>9.3%</td><td>8.7%</td><td>8.4%</td><td>9.1%</td></tr><tr><td>统计区间</td><td>雷曼公司（2）</td><td>合伙基金业绩（3）</td><td>有限合伙人收益（4）</td><td></td></tr><tr><td>---</td><td>---</td><td>---</td><td>---</td><td></td></tr><tr><td>1957年</td><td>-11.4%</td><td>10.4%</td><td>9.3%</td><td></td></tr><tr><td>1957-1958年</td><td>24.7%</td><td>55.6%</td><td>44.5%</td><td></td></tr><tr><td>1957-1959年</td><td>34.8%</td><td>95.9%</td><td>74.7%</td><td></td></tr><tr><td>1957-1960年</td><td>38.2%</td><td>140.6%</td><td>107.2%</td><td></td></tr><tr><td>1957-1961年</td><td>70.8%</td><td>251.0%</td><td>181.6%</td><td></td></tr><tr><td>1957-1962年</td><td>48.6%</td><td>299.8%</td><td>215.1%</td><td></td></tr><tr><td>1957-1963年6月30日</td><td>60.8%</td><td>355.8%</td><td>252.9%</td><td></td></tr><tr><td>年化复合收益率</td><td>7.6%</td><td>26.3%</td><td>21.4%</td><td></td></tr><tr><td>注：</td><td></td><td></td><td></td><td></td></tr></tbody></table><p>（1）基于年内资产净值变动+向持有人派发的全部分红计算得出。</p><p>（2）1957-1962年数据来自1963年《穆迪银行与金融手册》，1963年上半年为预估数据。</p><p>（3）1957-1961年数据，为所有前身有限合伙基金全年合并业绩，已扣除所有费用，未扣除向合伙人的利润分配及普通合伙人的业绩报酬。</p><p>（4）1957-1961年数据，基于前列合伙基金业绩，按照现行合伙协议约定的普通合伙人业绩报酬分配规则计算得出。</p><p>这些业绩数据持续证明：即便是拿着最高薪酬、最受尊敬的专业投资机构，也很难跑赢一个无人管理的蓝筹股指数。</p><p>这句话绝非对这些机构的指责。这些机构、投资顾问和信托部门，其投资方法、投资逻辑和业绩表现，都与上述投资公司基本一致。它们为数百万投资者提供了重要的价值：实现充分的分散化投资、带来投资的便利性与内心的安宁、帮助投资者避开劣质证券等等。但它们的服务，从来都不包括（绝大多数情况下，也从未声称包括）让资金以高于市场平均水平的利率复利增值。</p><p>我们合伙基金存在的根本意义，就是以高于市场平均的利率实现资金复利增值，同时相比上述投资工具，承担更低的长期本金亏损风险。我们当然无法保证一定能实现这个目标，但我们可以并且承诺：如果在任何合理的周期内（排除大规模的投机牛市），我们无法实现这一目标，我们就会停止运营。</p><h2 id="邓普斯特磨坊制造公司" tabindex="-1">邓普斯特磨坊制造公司 <a class="header-anchor" href="#邓普斯特磨坊制造公司" aria-label="Permalink to &quot;邓普斯特磨坊制造公司&quot;">​</a></h2><p>在最近的年度信中，我称哈里·博特尔为“年度人物”，现在看来，这个称呼还是低估了他。</p><p>去年，哈里完成了一项非凡的工作：将公司的非生产性资产转化为现金，而我们随即用这些现金，投资于被低估的证券。今年，哈里不仅继续将低效资产盘活变现，更让留存下来的核心资产实现了盈利。</p><p>过去十九个月里，公司的资产负债表发生了如下翻天覆地的变化（单位：千美元）：</p><h3 id="_1961年11月30日" tabindex="-1">1961年11月30日 <a class="header-anchor" href="#_1961年11月30日" aria-label="Permalink to &quot;1961年11月30日&quot;">​</a></h3><table tabindex="0"><thead><tr><th>资产项目</th><th>账面金额</th><th>估值折价率</th><th>调整后估值</th><th>负债与权益项目</th><th>账面金额</th></tr></thead><tbody><tr><td>现金</td><td>166</td><td>100%</td><td>166</td><td>应付票据</td><td>1230</td></tr><tr><td>应收账款（净额）</td><td>1040</td><td>85%</td><td>884</td><td>其他负债</td><td>1088</td></tr><tr><td>存货</td><td>4203</td><td>60%</td><td>2522</td><td>负债合计</td><td>2318</td></tr><tr><td>预付费用等</td><td>82</td><td>25%</td><td>21</td><td>账面净资产</td><td>4601</td></tr><tr><td>流动资产合计</td><td>5491</td><td>-</td><td>3593</td><td>快速变现调整后净资产</td><td>2120</td></tr><tr><td>人寿保险现金价值等</td><td>45</td><td>100%</td><td>45</td><td>总股本</td><td>60146股</td></tr><tr><td>固定资产净额</td><td>1383</td><td>拍卖净估值</td><td>800</td><td>调整后每股价值</td><td>35.25美元</td></tr><tr><td>资产总计</td><td>6919</td><td>-</td><td>4438</td><td>-</td><td>-</td></tr></tbody></table><h3 id="_1962年11月30日" tabindex="-1">1962年11月30日 <a class="header-anchor" href="#_1962年11月30日" aria-label="Permalink to &quot;1962年11月30日&quot;">​</a></h3><table tabindex="0"><thead><tr><th>资产项目</th><th>账面金额</th><th>估值折价率</th><th>调整后估值</th><th>负债与权益项目</th><th>账面金额</th></tr></thead><tbody><tr><td>现金</td><td>60</td><td>100%</td><td>60</td><td>应付票据</td><td>0</td></tr><tr><td>有价证券</td><td>758</td><td>1962年12月31日市值</td><td>834</td><td>其他负债</td><td>346</td></tr><tr><td>应收账款（净额）</td><td>796</td><td>85%</td><td>676</td><td>负债合计</td><td>346</td></tr><tr><td>存货</td><td>1634</td><td>60%</td><td>981</td><td>账面净资产</td><td>4077</td></tr><tr><td>人寿保险现金价值</td><td>41</td><td>100%</td><td>41</td><td>快速变现调整后净资产</td><td>3125</td></tr><tr><td>可收回所得税</td><td>170</td><td>100%</td><td>170</td><td>哈里·博特尔期权行权潜在收益</td><td>60</td></tr><tr><td>预付费用等</td><td>14</td><td>25%</td><td>4</td><td>总股本</td><td>60146股</td></tr><tr><td>流动资产合计</td><td>3473</td><td>-</td><td>2766</td><td>期权潜在新增股本</td><td>2000股</td></tr><tr><td>其他投资</td><td>5</td><td>100%</td><td>5</td><td>总股数</td><td>62146股</td></tr><tr><td>固定资产净额</td><td>945</td><td>拍卖净估值</td><td>700</td><td>调整后每股价值</td><td>51.26美元</td></tr><tr><td>资产总计</td><td>4423</td><td>-</td><td>3471</td><td>-</td><td>-</td></tr></tbody></table><h3 id="_1963年6月30日" tabindex="-1">1963年6月30日 <a class="header-anchor" href="#_1963年6月30日" aria-label="Permalink to &quot;1963年6月30日&quot;">​</a></h3><table tabindex="0"><thead><tr><th>资产项目</th><th>账面金额</th><th>估值折价率</th><th>调整后估值</th><th>负债与权益项目</th><th>账面金额</th></tr></thead><tbody><tr><td>现金</td><td>144</td><td>100%</td><td>144</td><td>应付票据（1963年7月3日已偿付）</td><td>125</td></tr><tr><td>有价证券</td><td>1772</td><td>1963年6月30日市值</td><td>2029</td><td>其他负债</td><td>394</td></tr><tr><td>应收账款（净额）</td><td>1262</td><td>85%</td><td>1073</td><td>负债合计</td><td>519</td></tr><tr><td>存货</td><td>977</td><td>60%</td><td>586</td><td>账面净资产</td><td>4582</td></tr><tr><td>预付费用等</td><td>12</td><td>25%</td><td>3</td><td>快速变现调整后净资产</td><td>4028</td></tr><tr><td>流动资产合计</td><td>4167</td><td>-</td><td>3835</td><td>总股本</td><td>62146股</td></tr><tr><td>其他投资</td><td>62</td><td>100%</td><td>62</td><td>调整后每股价值</td><td>64.81美元</td></tr><tr><td>固定资产净额</td><td>872</td><td>拍卖净估值</td><td>650</td><td>-</td><td>-</td></tr><tr><td>资产总计</td><td>5101</td><td>-</td><td>4547</td><td>-</td><td>-</td></tr><tr><td>上表中，我们依然沿用了此前对邓普斯特公司的估值折价标准，以反映非盈利资产的即时可变现价值。</td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><p>大家可以清晰地看到，哈里将资产变现的实际成效，远好于我当初估值时的保守预期。这主要归功于哈里的专业能力，或许也有一小部分原因，是我当初的估值本身就偏于保守。</p><p>同时大家也能看到，今年上半年，邓普斯特公司的主营业务实现了相当可观的经营利润（证券投资也带来了大幅的浮盈）。毫无疑问，经过调整后的经营业务，在大幅缩减的资产规模上，已经具备了至少中等水平的盈利能力。</p><p>但需要说明的是，受显著的季节性因素，以及前期亏损可抵扣所得税的影响，公司的真实盈利能力，远不能仅通过1962年11月30日和1963年6月30日的资产负债表对比来判断。</p><p>部分出于季节性因素，更重要的是1963年末前邓普斯特公司可能出现的新进展，在合伙基金上半年的业绩核算中，我们依然沿用1962年末51.26美元的每股估值，对邓普斯特持仓进行计量。但如果年末的最终估值低于这个数字，我会非常意外。</p><p>给我们团队里的基本面投资者补充一个细节：巴菲特合伙有限公司持有邓普斯特公司71.7%的股份，买入总成本为1,262,577.27美元。1963年6月30日，邓普斯特公司在奥马哈国民银行的一个小小保险箱里，就放着市值2,028,415.25美元的有价证券。我们持有的71.7%股份，对应这部分证券的价值就达到了1,454,373.70美元。</p><p>也就是说，仅这部分证券的价值，就已经超过了我们买入整家公司的全部成本，公司剩下的所有资产（地上的厂房设备、地下的资产等）全都是利润。我的证券分析师朋友们，可能会觉得这种记账方式太过原始，但我必须承认，相比祈祷有人愿意为明年的盈利付35倍市盈率，这种掰着手指头算账的方法，让我心里踏实得多。</p><h2 id="预付款与提前支取" tabindex="-1">预付款与提前支取 <a class="header-anchor" href="#预付款与提前支取" aria-label="Permalink to &quot;预付款与提前支取&quot;">​</a></h2><p>我们接受合伙人及潜在合伙人的提前出资，从资金到账日至年末，按6%的年利率支付利息。尽管我们不强制要求这笔资金在年末必须转为合伙基金的出资份额，但出资人在支付预付款时，应具备此意向。</p><p>同理，我们允许合伙人在年末前，提前支取不超过其合伙账户20%的资金，从支取日至年末，按6%的年利率收取利息，年末将支取金额从其资本金账户中扣除。同样，我们不希望合伙人把我们当成银行，这项权利仅用于应对突发的资金需求。</p><p>以6%的利率同时进行资金的借入与借出，听起来似乎“不像巴菲特的风格”。我们将提前支取权，视为给合伙人应对突发资金需求的流动性保障；而从实际情况来看，提前支取的金额，大概率会被提前出资的金额完全覆盖。</p><p>有人会问，既然我们能以更低的利率从商业银行借款，为什么还愿意以6%的利率接受提前出资？比如今年上半年，我们就以4%的利率，从银行获得了一笔金额不小的6个月期贷款。</p><p>答案是：长期来看，我们的投资收益率一定会高于6%（如果做不到，普通合伙人将拿不到任何业绩报酬，当然，短期能否达到6%，有很大的运气成分）。此外，对于这笔预计很快会成为我们权益资本金的资金，我的投资心态，和短期银行借款是完全不同的。</p><p>同时，提前出资也能让我们把新增资金的投资，平摊到全年，而不是每年1月集中面对一大笔新增资金的配置压力。另一方面，对于合伙人而言，6%的利率，也高于他们能从短期保本投资中获得的收益，因此我认为这是一项互利的安排。</p><p>1963年6月30日，我们的提前支取余额为21,832.00美元，提前出资余额为562,437.11美元。</p><h2 id="税务相关" tabindex="-1">税务相关 <a class="header-anchor" href="#税务相关" aria-label="Permalink to &quot;税务相关&quot;">​</a></h2><p>今年我们很可能会实现相当金额的已实现收益。当然，这件事最终也可能完全不会发生，而且它和我们今年的投资业绩本身没有任何关系。</p><p>我一直是一个坚定的“以低税率缴纳高额所得税”的倡导者。无数逻辑混乱、糟糕透顶的投资决策，都被所谓的“税务筹划”合理化了。</p><p>我的净资产，等于持仓的市场价值减去卖出时需要缴纳的税款。这笔税务负债，和资产一样真实——除非资产价格下跌（那就糟了）、资产被捐赠出去（不做评价），或者我持有到去世。而最后一种方式，即便能避税，也算得上是得不偿失的皮洛士式胜利了。</p><p>投资决策的核心准则，应该是在最低风险的前提下，最大化税后净资产的复利增值。死守低持仓成本的证券不放，本质上是把一部分净资产，锁定在与该证券相同的复利增速上。尽管个别案例中，这种做法可能带来好的结果，也可能带来坏的结果，但它本质上是放弃了主动投资管理。</p><p>从整体结果来看，投资者长期持有各类低持仓成本证券的收益，大概率会和持有全市场证券的平均水平一致，也就是与道指的复合收益率持平。我们认为，这并非税后复利收益率的最优解。</p><p>我此前也说过，如果合伙基金的收益，可能会占到你全年应纳税所得额的相当比例，最稳妥的做法，是按去年缴纳的税款金额，预缴今年的所得税。这样做，你绝对不会面临税务罚款。</p><p>无论如何，1963年1月1日加入合伙基金的出资人，今年的税务负担会非常低。根据我们的合伙协议，资本利得会优先分配给对应持仓浮盈的出资人。</p><p>和往年一样，我们会在11月1日左右，向各位合伙人，以及届时向我表达过入伙意向的投资者，发出一封信件，附上合伙协议修正案、1964年的出资承诺函、1963年税务情况预估等内容。</p><p>我每次在信的末尾，都欢迎大家就任何不明白的地方提问，但从来没人回应。或许根本没人读到这里。不管怎样，这个邀约依然有效。</p><p>此致</p><p>沃伦·E·巴菲特</p><p>巴菲特合伙有限公司</p><p>内布拉斯加州 奥马哈市 基维特广场810号</p><p>邮编31</p><p>1963年11月6日</p>',62)])])}const c=d(e,[["render",h]]);export{_ as __pageData,c as default};
